;EACA,qBAAA;EACA,kBAAA;EACA,UAAA;ANq2BF;AMn2BE;EACE,kBAAA;ANq2BJ;AC95DE;EKwjCA;IAII,kBAAA;ENs2BJ;AACF;;AMl2BA;EACE,kBAAA;ANq2BF;AMn2BE;EACE,kBAAA;EACA,WAAA;EACA,QAAA;EACA,2BAAA;ANq2BJ;;AMj2BA;EACE,YAAA;EACA,gBP1kCM;EO2kCN,gBAAA;EACA,kBAAA;ANo2BF;AMl2BE;EACE,qBPxlCY;EOylCZ,gBAAA;ANo2BJ;;AM/1BE;EACE,YAAA;ANk2BJ;;AM91BA;EACE,yBAAA;ANi2BF;;AM91BA;EACE,iBAAA;ANi2BF;;AM71BA;EACE,gCAAA;EACA,iBAAA;ANg2BF;;AM71BA,YAAA;ACjnCE;EACE,eAAA;EACA,qBAAA;APk9DJ;AOj9DI;EACE,gBAAA;EACA,cRLU;ACw9DhB;AOj9DI;EACE,cRRU;AC29DhB","file":"style.css","sourcesContent":["/*  typography */\n@import url('https://fonts.googleapis.com/css?family=Lexend:300,400,500,600,700');\n\nbody {\n  line-height: 1.2;\n  font-family: $primary-font;\n  -webkit-font-smoothing: antialiased;\n  font-size: 15px;\n  color: $text-color;\n}\n\np, .paragraph {\n  font-weight: 500;\n  color: $text-color;\n  font-size: 16px;\n  line-height: 1.7;\n  font-family: $primary-font;\n  text-align: justify;\n}\n\nh1,h2,h3,h4,h5,h6 {\n  color: $text-color-dark;\n  font-family: $primary-font;\n  font-weight: 700;\n  line-height: 1.2;\n}\n\nh1, .h1{\n  font-size: 60px;\n  @include mobile {\n    font-size: 45px;\n  }\n}\n\nh2, .h2{\n  font-size: 38px;\n  @include mobile {\n    font-size: 30px;\n  }\n}\n\nh3, .h3{\n  font-size: 25px;\n  @include mobile {\n    font-size: 20px;\n  }\n}\n\nh4, .h4{\n  font-size: 20px;\n  @include mobile {\n    font-size: 18px;\n  }\n}\n\nh5, .h5{\n  font-size: 18px;\n  @include mobile {\n    font-size: 16px;\n  }\n}\n\nh6, .h6{\n  font-size: 16px;\n  @include mobile {\n    font-size: 14px;\n  }\n}\n","// Color Variables\n$primary-color: #962F33;\n$secondary-color: #00041a;\n$third-color: #ffc5c7;\n$text-color: #5c5c77;\n$text-color-light: #8585a4;\n$text-color-dark: #1f1607;\n$body-color: #fff;\n$border-color: #ededf1;\n$black: #000;\n$white: #fff;\n$light: #f8f9fe;\n$gray: #f8f8f8;\n\n// Font Variables\n$primary-font: 'Lexend', sans-serif;\n$secondary-font: 'Lexend';\n$icon-font: 'themify';","/*  typography */\n@import url(\"https://fonts.googleapis.com/css?family=Lexend:300,400,500,600,700\");\nbody {\n  line-height: 1.2;\n  font-family: \"Lexend\", sans-serif;\n  -webkit-font-smoothing: antialiased;\n  font-size: 15px;\n  color: #5c5c77;\n}\n\np, .paragraph {\n  font-weight: 500;\n  color: #5c5c77;\n  font-size: 16px;\n  line-height: 1.7;\n  font-family: \"Lexend\", sans-serif;\n  text-align: justify;\n}\n\nh1, h2, h3, h4, h5, h6 {\n  color: #1f1607;\n  font-family: \"Lexend\", sans-serif;\n  font-weight: 700;\n  line-height: 1.2;\n}\n\nh1, .h1 {\n  font-size: 60px;\n}\n@media (max-width: 575px) {\n  h1, .h1 {\n    font-size: 45px;\n  }\n}\n\nh2, .h2 {\n  font-size: 38px;\n}\n@media (max-width: 575px) {\n  h2, .h2 {\n    font-size: 30px;\n  }\n}\n\nh3, .h3 {\n  font-size: 25px;\n}\n@media (max-width: 575px) {\n  h3, .h3 {\n    font-size: 20px;\n  }\n}\n\nh4, .h4 {\n  font-size: 20px;\n}\n@media (max-width: 575px) {\n  h4, .h4 {\n    font-size: 18px;\n  }\n}\n\nh5, .h5 {\n  font-size: 18px;\n}\n@media (max-width: 575px) {\n  h5, .h5 {\n    font-size: 16px;\n  }\n}\n\nh6, .h6 {\n  font-size: 16px;\n}\n@media (max-width: 575px) {\n  h6, .h6 {\n    font-size: 14px;\n  }\n}\n\n/* Button style */\n.btn {\n  font-size: 16px;\n  font-family: \"Lexend\", sans-serif;\n  text-transform: capitalize;\n  padding: 15px 40px;\n  border-radius: 0;\n  font-weight: 500;\n  border: 0;\n  position: relative;\n  z-index: 1;\n  transition: 0.2s ease;\n  overflow: hidden;\n  white-space: nowrap;\n}\n.btn::before {\n  position: absolute;\n  content: \"\";\n  height: 80%;\n  width: 100%;\n  left: 0;\n  bottom: 10%;\n  z-index: -1;\n  transition: transform 0.2s ease-in-out;\n  transform-origin: top;\n  transform: scaleY(0);\n}\n.btn:active, .btn:hover, .btn.focus, .btn:focus, .btn.active {\n  outline: 0;\n  box-shadow: none !important;\n}\n.btn:active::before, .btn:hover::before, .btn.focus::before, .btn:focus::before, .btn.active::before {\n  transform: scaleY(1);\n  transform-origin: bottom;\n}\n\n/* Button Disabled Style */\n.btn:disabled,\n.btn[disabled] {\n  cursor: not-allowed;\n  opacity: 0.6;\n  border: none;\n  pointer-events: none; /* Mencegah interaksi */\n}\n\n/* Jika ingin efek hover tetap ada tapi tidak aktif */\n.btn:disabled::before,\n.btn[disabled]::before {\n  display: none; /* Menghilangkan efek hover dari before */\n}\n\n.btn-sm {\n  font-size: 14px;\n  padding: 10px 35px;\n}\n\n.btn-xs {\n  font-size: 12px;\n  padding: 5px 15px;\n}\n\n.btn-primary {\n  color: #fff;\n  background-color: #962F33;\n}\n.btn-primary::before {\n  background-color: #fff;\n}\n.btn-primary:active, .btn-primary:hover, .btn-primary.focus, .btn-primary:focus, .btn-primary.active {\n  color: #962F33 !important;\n  background-color: #6f2326 !important;\n  border-color: #6f2326 !important;\n}\n\n.btn-outline-primary {\n  color: #962F33;\n  background-color: transparent;\n  border: 1px solid #962F33;\n}\n.btn-outline-primary::before {\n  background-color: #fff;\n}\n.btn-outline-primary:active, .btn-outline-primary:hover, .btn-outline-primary.focus, .btn-outline-primary:focus, .btn-outline-primary.active {\n  color: #962F33 !important;\n  background-color: #962F33 !important;\n  border-color: #962F33 !important;\n}\n\n.btn-light {\n  color: #962F33;\n  background-color: #fff;\n  border: 1px solid #fff;\n}\n.btn-light::before {\n  background-color: #962F33;\n}\n.btn-light:active, .btn-light:hover, .btn-light.focus, .btn-light:focus, .btn-light.active {\n  color: #fff !important;\n  background-color: #fff !important;\n  border: 1px solid #fff !important;\n}\n\n.btn-center {\n  align-items: center;\n}\n\nbody {\n  background-color: #fff;\n  overflow-x: hidden;\n}\n\n::selection {\n  background: #bd3b40;\n  color: #fff;\n}\n\n/* preloader */\n.preloader {\n  position: fixed;\n  top: 0;\n  left: 0;\n  right: 0;\n  bottom: 0;\n  background-color: #962F33;\n  z-index: 999999;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n}\n\nol,\nul {\n  list-s